// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract CollectibleSale {
    address private _owner;
    uint256 private _maxSupply;
    uint256 private _price;
    uint256 private _totalMinted;
    bool private _saleEnded;
    mapping(address => uint256) private _balances;

    event Buy(address indexed buyer, uint256 amount);

    constructor(uint256 maxSupply_, uint256 price_) {
        _owner = msg.sender;
        _maxSupply = maxSupply_;
        _price = price_;
        _saleEnded = false;
    }

    modifier onlyOwner() {
        require(msg.sender == _owner, "Not owner");
        _;
    }

    function maxSupply() public view returns (uint256) {
        return _maxSupply;
    }

    function price() public view returns (uint256) {
        return _price;
    }

    function totalMinted() public view returns (uint256) {
        return _totalMinted;
    }

    function saleEnded() public view returns (bool) {
        return _saleEnded;
    }

    function balances(address account) public view returns (uint256) {
        return _balances[account];
    }

    function buy(uint256 amount) external payable {
        require(!_saleEnded, "Sale ended");
        require(amount > 0, "Amount must be greater than 0");
        require(amount <= 10, "Amount exceeds limit per transaction");
        require(_totalMinted + amount <= _maxSupply, "Exceeds max supply");
        require(msg.value == amount * _price, "Exact payment required");

        _balances[msg.sender] += amount;
        _totalMinted += amount;

        if (_totalMinted >= _maxSupply) {
            _saleEnded = true;
        }

        emit Buy(msg.sender, amount);
    }

    function setPrice(uint256 newPrice) external onlyOwner {
        _price = newPrice;
    }

    function withdraw() external onlyOwner {
        payable(_owner).transfer(address(this).balance);
    }
}
